// Weights from WES Config node
const weights  = $('WES Config').first().json;
const wLike    = weights.weight_like    ?? 1;
const wComment = weights.weight_comment ?? 3;
const wShare   = weights.weight_share   ?? 5;
const wSave    = weights.weight_save    ?? 4;

// Use native JS Date.now() — safe in all n8n hosting environments
const weekAgo = Date.now() - (7 * 24 * 60 * 60 * 1000);

return $input.all().reduce((acc, item) => {
  const d = item.json;
  if (!d || Object.keys(d).length === 0) return acc;

  // Platform detection
  const isLinkedIn  = d.firstPublishedAt !== undefined || d.specificContent !== undefined;
  const isInstagram = d.permalink !== undefined && d.timestamp !== undefined;
  const isTwitter   = d.public_metrics !== undefined;

  // Direct timestamp extraction — no intermediate ISO string conversion
  let ts = null;
  if (d.firstPublishedAt)                                   ts = new Date(d.firstPublishedAt).getTime();
  else if (d.publishedDate || d.created_at || d.timestamp) ts = new Date(d.publishedDate || d.created_at || d.timestamp).getTime();

  if (!ts || isNaN(ts) || ts < weekAgo) return acc;

  const platform = d.platform
    || (isLinkedIn  ? 'linkedin'
    :  isInstagram  ? 'instagram'
    :  isTwitter    ? 'twitter'
    : 'unknown');

  const pm       = d.public_metrics || {};
  const likes    = pm.like_count     || d.like_count     || d.likes    || d.likeCount        || 0;
  const comments = pm.reply_count    || d.comments_count || d.comments || d.reply_count      || 0;
  const shares   = pm.retweet_count  || d.shares         || d.retweet_count || d.shareCount  || 0;
  const saves    = pm.bookmark_count || d.saves          || d.bookmark_count                 || 0;
  const impressions = pm.impression_count
    || d.impressions || d.view_count || d.reach
    || d.statistics?.totalShareStatistics?.impressionCount
    || null;

  const liText  = d.specificContent?.['com.linkedin.ugc.ShareContent']?.shareCommentary?.text || '';
  const rawText = liText || d.text || d.caption || '';

  const twitterUrl = isTwitter && d.id
    ? 'https://twitter.com/i/web/status/' + d.id
    : null;
  const url = d.url || d.permalink || twitterUrl || '#';

  acc.push({
    json: {
      _platform:    platform,
      _date:        new Date(ts).toISOString(),
      _likes:       likes,
      _comments:    comments,
      _shares:      shares,
      _saves:       saves,
      _impressions: impressions,
      _text:        rawText.trim(),
      _url:         url,
      _wLike:       wLike,
      _wComment:    wComment,
      _wShare:      wShare,
      _wSave:       wSave
    }
  });

  return acc;
}, []);

const errors = $input.all()
  .filter(i => i.json.error)
  .map(i => i.json.error?.message || 'Unknown error writing to Sheets');

return [{ json: { sheetErrors: errors, sheetErrorCount: errors.length } }];

// Use native JS Date.now() — safe in all n8n hosting environments
const items = $input.all();
let totalImpressions = 0;
let totalWesSum = 0;
let postsWithImpressions = 0;
let postsWithoutImpressions = 0;
let bestPost = null;
let worstPost = null;
const platformStats = {};

items.forEach(item => {
  const d = item.json;
  if (!d || Object.keys(d).length === 0) return;

  const wLike    = d._wLike    ?? 1;
  const wComment = d._wComment ?? 3;
  const wShare   = d._wShare   ?? 5;
  const wSave    = d._wSave    ?? 4;

  const platform    = d._platform;
  const likes       = d._likes    || 0;
  const comments    = d._comments || 0;
  const shares      = d._shares   || 0;
  const saves       = d._saves    || 0;
  const impressions = d._impressions;
  const wes         = (wLike * likes) + (wComment * comments) + (wShare * shares) + (wSave * saves);

  if (!platformStats[platform]) {
    platformStats[platform] = { posts: 0, impressions: 0, wesSum: 0, postsWithImpressions: 0 };
  }
  platformStats[platform].posts++;

  if (impressions !== null && impressions > 0) {
    const rate = (wes / impressions) * 100;
    platformStats[platform].impressions          += impressions;
    platformStats[platform].wesSum               += wes;
    platformStats[platform].postsWithImpressions++;
    totalImpressions    += impressions;
    totalWesSum         += wes;
    postsWithImpressions++;

    const postPayload = { platform, text: d._text || 'Media post', rate, url: d._url };
    if (!bestPost  || rate > bestPost.rate)  bestPost  = postPayload;
    if (!worstPost || rate < worstPost.rate) worstPost = postPayload;
  } else {
    postsWithoutImpressions++;
  }
});

const platformRankings = Object.entries(platformStats)
  .map(([name, s]) => ({
    name,
    avgEngagementRate: s.postsWithImpressions > 0
      ? ((s.wesSum / s.impressions) * 100).toFixed(2)
      : 'N/A',
    totalPosts:       s.posts,
    totalImpressions: s.impressions
  }))
  .sort((a, b) => parseFloat(b.avgEngagementRate) - parseFloat(a.avgEngagementRate));

// Native JS date math — no Luxon dependency
const now      = new Date();
const weekAgo  = new Date(now.getTime() - (7 * 24 * 60 * 60 * 1000));
const toISODate = d => d.toISOString().slice(0, 10);

return [{
  json: {
    weekStart:               toISODate(weekAgo),
    weekEnd:                 toISODate(now),
    totalPosts:              items.length,
    postsWithImpressions,
    postsWithoutImpressions,
    totalImpressions,
    avgEngagementRate: postsWithImpressions > 0
      ? ((totalWesSum / totalImpressions) * 100).toFixed(2)
      : 'N/A',
    platformRankings,
    bestPost,
    worstPost
  }
}];
